INSERT INTO `video` (`V_id`, `V_Title`, `V_Url`, `V_Remarks`) VALUES
(1, 'Java Introduction', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/MT6J2oqxPow?si=LbnubcHXEkh8Fx-u\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'what is Java? <br><br>\r\nJava is a high-level, object-oriented programming language developed by Sun Microsystems (now owned by Oracle) in 1995. It is platform-independent due to its \"Write Once, Run Anywhere\" (WORA) capability, achieved using the Java Virtual Machine (JVM). <br><br>\r\n\r\nfeatures of Java <br>\r\n1.  Simple and easy to learn <br>\r\n2.  Object-oriented programming <br>\r\n3.  Compiled and interpreted <br>\r\n4.  Platform independent <br>\r\n5.  Robust and secure <br>\r\n6.  Distributed <br>\r\n7.  Multithreaded <br>\r\n8.  High performance <br>\r\n9.  Dynamic <br>\r\n10. Scalability <br><br>\r\n\r\nApplications of Java<br><br>\r\n1.  Web Applications â Used for building dynamic websites and web services (e.g., Spring, Java EE). <br>\r\n2.  Mobile Applications â Powers Android app development using Java and Kotlin. <br>\r\n3.  Desktop Applications â Used for GUI-based applications with JavaFX and Swing. <br>\r\n4.  Enterprise Applications â Common in large-scale applications like banking and ERP systems. <br>\r\n5.  Cloud Computing â Supports cloud-based services (e.g., AWS, Google Cloud). <br>\r\n6.  Big Data & Analytics â Used in tools like Apache Hadoop and Spark. <br>\r\n7.  Internet of Things (IoT) â Embedded systems and IoT applications (e.g., Raspberry Pi). <br>\r\n8.  Game Development â Used in game engines like LibGDX and jMonkeyEngine.<br>\r\n9.  Scientific Computing â Used for simulations, research, and mathematical calculations. <br>\r\n10. AI & Machine Learning â Libraries like DeepLearning4J and Weka support AI development. <br>\r\n11. Networking Applications â Used for chat applications, servers, and remote-control apps. <br>\r\n12. Cybersecurity â Helps build secure applications with cryptographic algorithms. <br>\r\n13. Blockchain Development â Used in blockchain projects like Hyperledger Fabric. <br>\r\n14. Testing & Automation â Powers testing tools like Selenium and JUnit. <br>\r\n15. DevOps & CI/CD â Integrated in CI/CD pipelines using Jenkins, Docker, and Kubernetes. <br>'),
(2, 'History of Java', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/mglWM6PKZVk?si=JaEW5IzrXZXEAdLO\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'History of Java Programming<br><br>\r\nJava was created by James Gosling and his team at Sun Microsystems in 1991. Initially, it was called \"Oak\", but later renamed Java in 1995. It was designed to be a platform-independent, secure, and object-oriented programming language. <br>\r\nIn 2009, Oracle Corporation acquired Sun Microsystems, making Java a key part of Oracle\'s software ecosystem. Today, Java is one of the most widely used programming languages worldwide. <br><br>\r\n\r\nEvolution of Java<br><br>\r\nJava has evolved through multiple versions, introducing new features and enhancements over time.<br>\r\n1991 â Java project (Oak) started at Sun Microsystems.<br>\r\n1995 â Java 1.0 officially released.<br>\r\n1998 â Java 2 introduced, with Standard (J2SE), Enterprise (J2EE), and Micro (J2ME) editions.<br>\r\n2004 â Java 5 introduced generics, enhanced loops, and multithreading improvements.<br>\r\n2011 â Java 7 introduced try-with-resources and NIO enhancements.<br>\r\n2014 â Java 8 introduced Lambda Expressions and the Stream API.<br>\r\n2017 â Java 9 introduced the modular system (Project Jigsaw).<br>\r\n2018âPresent â Regular updates with new versions every six months, improving performance, security, and modern development practices<br> <br>\r\n\r\nWhy the Name is \"Java\"? <br><br>\r\nOriginally named \"Oak\", the name was changed to Java due to trademark issues. The developers wanted a unique, catchy name. Inspired by their love for coffee, they chose \"Java\" after the Java coffee from Indonesia. This is why the coffee cup logo represents Java. <br>'),
(3, 'Setting Up Java Development Environment (JDK & IDE', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/pa4DAOYOAAM?si=AxpCK6vZ78OZut3z\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'Java Installation\r\n1. Download & Install Java (JDK)<br>\r\nVisit Oracle JDK Download. <br>\r\n\r\nDownload and install the latest JDK version.<br><br>\r\n\r\n2. Set Up Environment Variables<br>\r\nGo to Control Panel > System > Advanced System Settings > Environment Variables.\r\n<br>\r\nUnder System Variables, add/edit:\r\n<br>\r\nJAVA_HOME = C:\\Program Files\\Java\\jdk-XX.X.X (your installed JDK path).\r\n<br>\r\nAdd C:\\Program Files\\Java\\jdk-XX.X.X\\bin to Path variable.\r\n<br><br>\r\n3. Verify Installation<br>\r\nOpen Command Prompt (Win + R ? cmd ? Enter).\r\n<br>\r\nRun:<br>\r\njava -version<br>\r\njavac -version<br>\r\nIf Java is installed correctly, it will show the version.<br><br>\r\n\r\n4. Write Java Code in Notepad<br>\r\nOpen Notepad and type:<br>\r\nclass Hello {<br>\r\n    public static void main(String[] args) {<br>\r\n        System.out.println(\"Hello, Java!\");<br>\r\n    }<br>\r\n}<br><br>\r\nSave the file as Hello.java (with .java extension) in a specific folder (e.g., C:\\JavaPrograms).<br><br>\r\n\r\n5. Compile & Run Java Program in Command Prompt<br>\r\nOpen Command Prompt and navigate to the folder:<br>\r\ncd C:\\JavaPrograms<br><br>\r\nCompile the Java file:<br>\r\njavac Hello.java<br><br>\r\nRun the program:\r\n<br>\r\njava Hello\r\n<br><br>\r\nOutput:<br>\r\nHello, Java! \r\nNow, you\'ve successfully installed Java and compiled a simple program using Notepad and Command Prompt. \r\n\r\n6. Configure an IDE (Optional but Recommended)<br><br>\r\nDownload and install an IDE like:\r\n<br>\r\nIntelliJ IDEA: https://www.jetbrains.com/idea/\r\n<br>\r\nEclipse: https://www.eclipse.org/downloads/\r\n<br>\r\nVS Code (with Java Extension Pack): https://code.visualstudio.com/\r\n<br><br>\r\nTip: If using VS Code, install the Java extension pack for better support.'),
(4, 'Writing Your First Java Program', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/LCOxwjh1Go8?si=4rVtOR6SNO6wJgLB\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'Compile and Run Java Code Using Notepad and Command Prompt<br>\r\nThis method is useful for beginners who want to run Java without an IDE.<br>\r\n\r\nStep 1: Write Java Code in Notepad<br>\r\nOpen Notepad and type the following Java code:\r\n\r\n<br><br>\r\nclass HelloWorld {<br>\r\n    public static void main(String[] args) {<br>\r\n        System.out.println(\"Hello, Java!\");<br>\r\n    }\r\n}<br><br>\r\nSave the file as HelloWorld.java<br>\r\n\r\nSelect File ? Save As<br>\r\n\r\nChange \"Save as type\" to \"All Files\"<br>\r\n\r\nSave it as HelloWorld.java in a specific folder (e.g., C:\\JavaPrograms)<br><br>\r\n\r\nStep 2: Open Command Prompt and Navigate to File Location<br>\r\nPress Win + R, type cmd, and press Enter.<br>\r\nNavigate to the folder where the file is saved using the cd command:<br>\r\n\r\n\r\ncd C:\\JavaPrograms<br><br>\r\nTip: Use dir to check if the file is present.<br><br>\r\n\r\nStep 3: Compile the Java Program<br>\r\nRun the following command to compile:<br>\r\n\r\njavac HelloWorld.java<br><br>\r\n\r\nTip: If there\'s no output, it means the compilation was successful. If there are errors, fix them in Notepad and recompile.\r\n<br><br>\r\nStep 4: Run the Java Program<br>\r\nRun the compiled Java program using:<br>\r\n\r\njava HelloWorld<br>\r\noutput <br> Hello, Java!<br><br>\r\n\r\nTip: Do NOT include .class or .java when running the program. Use only java HelloWorld.\r\n<br><br>\r\nJava Program Successfully Compiled and Run!<br>\r\nNow, you can start writing and executing Java programs using Notepad and Command Prompt.'),
(5, 'Understanding Java Syntax and Structure', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/Cea_VSHlUNU?si=2Dw_Xxg9W1-8h9gq\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'Java Basic Syntax and Rules \r\n<br>\r\n1. Basic Structure of a Java Program<br>\r\nA simple Java program looks like this:<br>\r\n// Example of a basic Java program\r\npublic class HelloWorld {<br>\r\n    public static void main(String[] args) {<br>\r\n        System.out.println(\"Hello, World!\"); // Print statement<br>\r\n    }<br>\r\n}<br>\r\nExplanation:<br>\r\npublic class HelloWorld - Defines a class named HelloWorld.\r\n<br>\r\npublic static void main(String[] args) - This is the main method where execution starts.\r\n<br>\r\nSystem.out.println(\"Hello, World!\"); - Prints output to the console.\r\n<br><br><br>\r\n2. Java Syntax Rules<br>\r\na) Case Sensitivity<br>\r\nJava is case-sensitive, meaning HelloWorld and helloworld are different.\r\n<br><br>\r\nb) Class Names\r\nClass names should start with an uppercase letter:\r\n<br>\r\npublic class MyClass { }<br><br>\r\nc) Method Names<br>\r\nMethod names should start with a lowercase letter and use camelCase:\r\n<br>\r\npublic void myMethod() { }<br><br>\r\nd) File Name<br>\r\nThe filename must match the public class name and end with .java:<br>\r\nFile: HelloWorld.java<br><br><br>\r\n3. Java Identifiers and Keywords<br>\r\na) Identifiers<br>\r\nIdentifiers are names given to variables, methods, classes, etc. <br>\r\nExample:int age;<br>\r\nString studentName;<br><br>\r\nb) Reserved Keywords<br>\r\nJava has special keywords that cannot be used as identifiers.\r\n<br>\r\nExamples: class, public, static, void, if, else, for, while, etc.\r\n<br><br><br>\r\n4. Comments in Java<br>\r\nUsed for documentation and ignored by the compiler.\r\n<br><br>\r\nSingle-line comment:<br>\r\n// This is a single-line comment<br><br>\r\nMulti-line comment:\r\n<br>\r\n/*<br>\r\n This is a multi-line comment<br>\r\n*/<br><br>\r\nJavadoc comment (for documentation):<br>\r\n\r\n/**<br>\r\n * This method prints a message.<br>\r\n */<br>\r\npublic void showMessage() { }<br>'),
(6, 'Variables and Data Types', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/O8rar3Y4mnI?si=bwW0TP0UKDQS4hzG\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/LusTv0RlnSU?si=VeJxpOIJ1ZqhxX2D\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'Java Data types | Variables in java\r\n\r\nJava Data Types<br>\r\nJava is a statically typed language, meaning that every variable must have a declared type. Java has two main categories of data types:<br><br>\r\n\r\nA. Primitive Data Types<br>\r\nThese are built-in types that store simple values directly in memory. Java has 8 primitive data types:<br><br>\r\n\r\n1.byte <br>\r\nsize:1 byte <br>	\r\ndescription: Stores whole numbers from -128 to 127<br><br>\r\n2.short	 <br>      \r\nsize:2 bytes<br>		\r\ndescription:Stores whole numbers from -32,768 to 32,767<br><br>\r\n3.int	<br>       \r\nsize:4 bytes<br>		\r\ndescription:Stores whole numbers from -2^31 to 2^31-1<br><br>\r\n4.long	       <br>\r\nsize:8 bytes	<br>	\r\ndescription:Stores large whole numbers from -2^63 to 2^63-1<br><br>\r\n5.float	       <br>\r\nsize:4 bytes	<br>	\r\ndescription:Stores decimal numbers (single precision) <br><br>\r\n6.double	       <br>\r\nsize:8 bytes		<br>\r\ndescription:Stores decimal numbers (double precision) <br><br>\r\n7.char	       <br>\r\nsize:2 bytes	<br>	\r\ndescription:Stores a single character (Unicode)<br><br>\r\n8.boolean	       <br>\r\nsize:1 bit		<br>\r\ndescription:Stores true or false values<br><br>\r\nExample of Primitive Data Types in Java:<br><br>\r\n\r\npublic class PrimitiveExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        byte smallNumber = 100;<br>\r\n        short shortNumber = 30000;<br>\r\n        int intNumber = 123456;<br>\r\n        long longNumber = 123456789L;<br>\r\n        float floatNumber = 12.34f;<br>\r\n        double doubleNumber = 123.456;<br>\r\n        char character = \'A\';<br>\r\n        boolean isJavaFun = true;<br>\r\n\r\n        System.out.println(\"Byte: \" + smallNumber);<br>\r\n        System.out.println(\"Short: \" + shortNumber);<br>\r\n        System.out.println(\"Int: \" + intNumber);<br>\r\n        System.out.println(\"Long: \" + longNumber);<br>\r\n        System.out.println(\"Float: \" + floatNumber);<br>\r\n        System.out.println(\"Double: \" + doubleNumber);<br>\r\n        System.out.println(\"Char: \" + character) ;<br>\r\n        System.out.println(\"Boolean: \" + isJavaFun);<br>\r\n    }\r\n}<br><br>\r\nB. Non-Primitive Data Types<br>\r\nNon-primitive data types are reference types that store memory addresses rather than actual values.<br><br>\r\n\r\n1. String - A sequence of characters<br>\r\n2. Array - A collection of similar data elements<br>\r\n3. Class - A blueprint for creating objects<br>\r\n4. Interface - A blueprint for multiple class implementation<br>\r\n5. Enum - A special class representing constants<br>\r\n<br>\r\nExample of Non-Primitive Data Types:<br>\r\n<br>\r\npublic class NonPrimitiveExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        String message = \"Hello, Java!\";<br>\r\n        int[] numbers = {10, 20, 30, 40, 50};<br>\r\n        \r\n        System.out.println(\"String: \" + message);<br>\r\n        System.out.println(\"First element of array: \" + numbers[0]);<br>\r\n    }\r\n}<br><br><br>\r\n\r\nVariables in Java<br>\r\nA variable is a named memory location used to store a value. In Java, variables must be declared with a data type before use. <br>\r\n\r\nTypes of Variables<br><br>\r\n1.Local Variable<br>	\r\nscope:Inside a method/block<br>	\r\nmemory allocation:Created when method starts, destroyed after execution	<br>\r\ndefault value:No default value (must be initialized) <br><br>\r\n2.Instance Variable	<br>\r\nscope:Inside a class, outside methods	<br>\r\nmemory allocation:Allocated in heap memory<br>	\r\nDefault values:0, null, false, etc.<br><br>\r\n3.Static Variable	<br>\r\nscope:Declared with static keyword	<br>\r\nmemory allocation:Shared among all instances of a class	<br><br>\r\nExample of Different Variables in Java:<br>\r\nclass VariableExample {<br>\r\n    // Instance variable<br>\r\n    int instanceVar = 10;<br>\r\n    <br>\r\n    // Static variable<br>\r\n    static String staticVar = \"I am static\";\r\n    <br><br>\r\n    public void showVariables() {<br>\r\n        // Local variable<br>\r\n        int localVar = 5;<br>\r\n        System.out.println(\"Local Variable: \" + localVar);<br>\r\n        System.out.println(\"Instance Variable: \" + instanceVar);<br>\r\n        System.out.println(\"Static Variable: \" + staticVar);<br>\r\n    }\r\n<br><br>\r\n    public static void main(String[] args) {<br>\r\n        VariableExample obj = new VariableExample();<br>\r\n        obj.showVariables();<br>\r\n    }\r\n}<br><br>\r\nKey Points to Remember<br>\r\n- Java is statically typed, so every variable must have a declared type.<br>\r\n- Primitive types store values directly, whereas non-primitive types store references.<br>\r\n- Local variables must be initialized before use.<br>\r\n- Static variables belong to the class, not instances.<br>'),
(7, 'Operators in Java', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/Oud4alVQU4s?si=cbNG5BNGdb-IVqbk\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/_AQzA-T6QSk?si=NvSTiyftIufb8nDQ\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/3Uay7U50hLY?si=w5zELWWhOiO_0uOW\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', '1. Operators & Binary Number System | 2. Operators in Java | Types of operators with practical examples | 3. Implementation of Logical and Boolean Logical<br><br>\r\n\r\nOperator in Java<br><br>\r\n\r\n1. Arithmetic Operators<br>\r\nThese operators are used to perform basic mathematical operations.<br><br>\r\n\r\nOperator :	Description<br>\r\n+ : Addition<br>\r\n- : 	Subtraction<br>\r\n* :	Multiplication<br>\r\n/ :	Division<br>\r\n% :	Modulus (Remainder)<br><br>\r\nExample:<br>\r\n\r\nint a = 10, b = 5;<br>\r\nSystem.out.println(a + b); // 15<br>\r\nSystem.out.println(a - b); // 5<br>\r\nSystem.out.println(a * b); // 50<br>\r\nSystem.out.println(a / b); // 2<br>\r\nSystem.out.println(a % b); // 0<br><br>\r\n2. Relational (Comparison) Operators<br>\r\nThese operators compare two values and return a Boolean (true or false).<br>\r\n\r\nOperator : Description<br>\r\n== : Equal to<br>\r\n!= : Not equal to<br>\r\n> : Greater than<br>\r\n< : Less than<br>\r\n>= : Greater than or equal to<br>\r\n<= : Less than or equal to<br><br>\r\nExample:<br>\r\n\r\nint x = 10, y = 20;<br>\r\nSystem.out.println(x == y); // false<br>\r\nSystem.out.println(x != y); // true<br>\r\nSystem.out.println(x > y);  // false<br>\r\nSystem.out.println(x < y);  // true<br><br>\r\n3. Logical Operators<br>\r\nUsed for logical operations, mainly in control flow.\r\n<br>\r\nOperator:Description<br>\r\n&&: Logical AND	<br>\r\n!: Logical NOT<br><br>\r\nExample:<br>\r\n\r\nboolean a = true, b = false;<br>\r\nSystem.out.println(a && b); // false<br>\r\nSystem.out.println(a || b); // true<br>\r\nSystem.out.println(!a);     // false<br><br>\r\n4. Bitwise Operators<br>\r\nOperate at the bit level.<br><br>\r\n\r\nOperator:Description<br>\r\n&:Bitwise AND<br>\r\n^:Bitwise XOR<br>\r\n~:Bitwise Complement<br>\r\n<<:Left Shift<br>\r\n>>:Right Shift<br>\r\n>>>:Unsigned Right Shift<br><br>\r\nExample:<br>\r\n\r\nint a = 5, b = 3;<br>\r\nSystem.out.println(a & b);  // 1 (0101 & 0011 = 0001)<br>\r\nSystem.out.println(a | b);  // 7 (0101 | 0011 = 0111)<br>\r\nSystem.out.println(a ^ b);  // 6 (0101 ^ 0011 = 0110)<br>\r\nSystem.out.println(~a);     // -6 (~0101 = 1010 in 2\'s complement)<br><br>\r\n5. Assignment Operators<br>\r\nUsed to assign values to variables.<br>\r\n\r\nOperator:Equivalent To<br>\r\n=	: a = b<br>\r\n+=	: a += b<br>	\r\n-=	: a -= b<br>	\r\n*=	: a *= b<br>	\r\n/=	: a /= b<br>	\r\n%=	: a %= b<br><br>	\r\nExample:<br>\r\n\r\nint a = 10;<br>\r\na += 5;  // a = 15<br>\r\na *= 2;  // a = 30<br>\r\nSystem.out.println(a);<br><br>\r\n6. Unary Operators<br>\r\nOperate on a single operand.<br>\r\n<br>\r\nOperator : 	Description<br>\r\n+ : Unary Plus (positive)<br>\r\n- : Unary Minus (negative)<br>\r\n++ :	Increment (pre/post)<br>\r\n-- : Decrement (pre/post)<br><br>\r\nExample:<br>\r\n\r\nint x = 10;<br>\r\nSystem.out.println(++x); // 11 (Pre-increment)<br>\r\nSystem.out.println(x--); // 11 (Post-decrement)<br>\r\nSystem.out.println(x);   // 10<br><br>\r\n7. Ternary Operator<br>\r\nShortens an if-else condition.<br>\r\n\r\nOperator:Example<br>\r\n? :	condition ? value_if_true : value_if_false\r\nExample:\r\n<br>\r\nint a = 10, b = 20;<br>\r\nint min = (a < b) ? a : b;<br>\r\nSystem.out.println(min); //output: 10<br><br>\r\n8. Instanceof Operator<br>\r\nChecks whether an object belongs to a specific class.\r\n<br>\r\nExample:\r\n<br>\r\nString str = \"Hello\";<br>\r\nSystem.out.println(str instanceof String); //output: true<br><br>\r\n9. Type Cast Operator<br>\r\nUsed to convert one data type into another.\r\n<br><br>\r\nExample:<br>\r\ndouble d = 10.5;<br>\r\nint i = (int) d; // Explicit casting<br>\r\nSystem.out.println(i); // output:10'),
(8, 'Control Flow Statements ', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/OTMsKM8OZNQ?si=gQbdWiM4Wb0sdgRq\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'Java Control Statements: <br><br>\r\n\r\n1. If Statement<br><br>\r\nThe if statement executes a block of code only if a given condition evaluates to true.<br><br>\r\n\r\nSyntax:<br>\r\nif (condition) {<br>\r\n    // Code to execute if the condition is true\r\n}<br><br>\r\nExample:<br>\r\nint number = 10;<br>\r\nif (number > 0) {<br>\r\n    System.out.println(\"The number is positive.\");\r\n}<br><br>\r\nOutput:<br>\r\nThe number is positive.<br>\r\n2. If-Else Statement<br>\r\nThe if-else statement provides an alternative block of code to execute if the condition is false.<br><br>\r\n\r\nSyntax:<br>\r\nif (condition) {<br>\r\n    // Code to execute if the condition is true<br>\r\n} else {<br>\r\n    // Code to execute if the condition is false<br>\r\n}<br><br>\r\nExample:<br>\r\nint number = -5;<br>\r\nif (number > 0) {<br>\r\n    System.out.println(\"The number is positive.\");<br>\r\n} else {<br>\r\n    System.out.println(\"The number is not positive.\");\r\n}<br><br>\r\nOutput:<br>\r\nThe number is not positive.<br><br>\r\n3. If-Else-If Ladder<br>\r\nWhen multiple conditions need to be checked, we can use the if-else-if ladder.<br>\r\n<br><br>\r\nSyntax:<br>\r\nif (condition1) {<br>\r\n    // Code for condition1<br>\r\n} else if (condition2) {<br>\r\n    // Code for condition2<br>\r\n} else {<br>\r\n    // Code if none of the conditions are true<br>\r\n}<br><br>\r\nExample:<br>\r\nint marks = 85;<br>\r\nif (marks >= 90) {<br>\r\n    System.out.println(\"Grade: A\");<br>\r\n} else if (marks >= 75) {<br>\r\n    System.out.println(\"Grade: B\");<br>\r\n} else if (marks >= 60) {<br>\r\n    System.out.println(\"Grade: C\");<br>\r\n} else {<br>\r\n    System.out.println(\"Grade: D\");\r\n}<br><br>\r\nOutput:<br>\r\nGrade: B<br><br>\r\n4. Switch Case<br>\r\nThe switch statement is used to execute one block of code out of many options based on the value of an expression.<br><br>\r\n\r\nSyntax:<br>\r\nswitch (expression) {<br>\r\n    case value1:<br>\r\n        // Code to execute for value1<br>\r\n        break;<br>\r\n    case value2:<br>\r\n        // Code to execute for value2<br>\r\n        break;<br>\r\n    ...<br>\r\n    default:<br>\r\n        // Code to execute if no case matches\r\n}<br><br>\r\nExample:<br>\r\nint day = 3;<br>\r\nswitch (day) {<br>\r\n    case 1:<br>\r\n        System.out.println(\"Sunday\");<br>\r\n        break;<br>\r\n    case 2:<br>\r\n        System.out.println(\"Monday\");<br>\r\n        break;<br>\r\n    case 3:<br>\r\n        System.out.println(\"Tuesday\");<br>\r\n        break;<br>\r\n    default:<br>\r\n        System.out.println(\"Invalid day\");\r\n}<br><br>\r\nOutput:\r\n<br>\r\nTuesday'),
(9, 'Java Loops', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/30xvczNMAUs?si=dmIYyUEmm07lmBUx\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/GjHNGM7KN3w?si=hlJWwk4JOjH6oP-D\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/Dr4PpNa7AYo?si=deHhSZDmTfywFkAh\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', '\r\nJava Loops: For, While, & Do-While<br><br>\r\nLoops in Java allow you to execute a block of code multiple times based on a condition. Java provides three primary loop constructs:\r\n<br>\r\nfor loop â Best for situations where the number of iterations is known.\r\n<br>\r\nwhile loop â Ideal when the number of iterations is unknown but depends on a condition.\r\n<br>\r\ndo-while loop â Similar to the while loop but guarantees at least one execution.\r\n<br><br>\r\nfor Loop<br>\r\nThe for loop is commonly used when the number of iterations is predetermined.\r\n<br><br>\r\nSyntax:<br>\r\nfor (initialization; condition; update) {<br>\r\n    // Code to execute\r\n}<br><br>\r\nExample: Printing numbers from 1 to 5<br>\r\npublic class ForLoopExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        for (int i = 1; i <= 5; i++) {<br>\r\n            System.out.println(i);\r\n        }\r\n    }\r\n}<br><br>\r\nHow it works:<br>\r\n\r\nint i = 1; // Initializes the loop variable.\r\n<br>\r\ni <= 5; // Condition to check before each iteration.\r\n<br>\r\ni++ // Increments i after each loop execution.\r\n<br><br>\r\nwhile Loop<br>\r\nThe while loop is used when the number of iterations is not known in advance.\r\n<br>\r\nSyntax:<br>\r\nwhile (condition) {<br>\r\n    // Code to execute\r\n}<br><br>\r\nExample: Print numbers from 1 to 5\r\n<br><br>\r\npublic class WhileLoopExample {\r\n    public static void main(String[] args) {\r\n        int i = 1;\r\n        while (i <= 5) {\r\n            System.out.println(i);\r\n            i++; // Increment to avoid infinite loop\r\n        }\r\n    }\r\n}<br><br>\r\nHow it works:\r\n<br>\r\nChecks the condition first (i <= 5).\r\n<br>\r\nExecutes the block if the condition is true.\r\n<br>\r\nRepeats until the condition is false.\r\n<br><br>\r\ndo-while Loop<br>\r\nThe do-while loop is similar to while, but it executes at least once, even if the condition is false.\r\n<br>\r\nSyntax:\r\n<br>\r\ndo {<br>\r\n    // Code to execute<br>\r\n} while (condition);<br>\r\nExample: Print numbers from 1 to 5\r\n<br><br>\r\npublic class DoWhileExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        int i = 1;<br>\r\n        do {<br>\r\n            System.out.println(i);<br>\r\n            i++;<br>\r\n        } while (i <= 5);\r\n    }\r\n}<br><br>\r\nHow it works:<br>\r\n\r\nExecutes the block at least once before checking the condition.<br>\r\n\r\nIf the condition is true, it repeats execution.\r\n<br>\r\n<br>Example: Finding the Sum of First 5 Numbers Using Each Loop<br>\r\nUsing for Loop<br><br>\r\n\r\nint sum = 0;<br>\r\nfor (int i = 1; i <= 5; i++) {<br>\r\n    sum += i;<br>\r\n}<br>\r\nSystem.out.println(\"Sum: \" + sum);<br><br>\r\nUsing while Loop<br><br>\r\nint sum = 0, i = 1;<br>\r\nwhile (i <= 5) {<br>\r\n    sum += i;<br>\r\n    i++;<br>\r\n}<br>\r\nSystem.out.println(\"Sum: \" + sum);<br><br>\r\nUsing do-while Loop<br><br>\r\nint sum = 0, i = 1;<br>\r\ndo {<br>\r\n    sum += i;<br>\r\n    i++;<br>\r\n} while (i <= 5);<br>\r\nSystem.out.println(\"Sum: \" + sum);'),
(10, 'Functions & Methods', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/qcSz4ef9UHA?si=nzKC9wkEqDXw_buj\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/4MJ0YHNzT1w?si=rFcVh2kDaIAyAc18\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', '\r\n\r\n1. What is a Method in Java?<br><br>\r\nA method in Java is a reusable block of code that executes a specific action. Methods help in reducing redundancy and improving code readability.\r\n<br><br>\r\n2. Syntax of a Method\r\n<br><br>\r\nreturnType methodName(parameters) {<br>\r\n    // Method body<br>\r\n    return value; // (if returnType is not void)\r\n}<br><br>\r\nExample<br><br>\r\n<br><br>\r\npublic class Example {<br>\r\n    public static void greet() {<br>\r\n        System.out.println(\"Hello, welcome to Java!\");\r\n    }\r\n<br>\r\n    public static void main(String[] args) {<br>\r\n    <br>    greet(); // Calling the method\r\n    }\r\n}<br><br>\r\nOutput:<br>\r\n\r\nHello, welcome to Java!<br><br>\r\n3. Types of Methods<br><br>\r\nA. Predefined (Built-in) Methods<br>\r\n<br>Java provides many predefined methods from standard libraries, such as:\r\n<br>\r\nMath.sqrt(25) ? Returns square root of 25.\r\n<br>\r\nSystem.out.println(\"Hello\") ? Prints output to the console.<br>\r\n\r\nB. User-Defined Methods<br><br>\r\nThese are methods that developers create based on their needs.\r\n<br>\r\nExample:<br>\r\n\r\n\r\npublic class Calculator {<br>\r\n    public static int add(int a, int b) {<br>\r\n        return a + b;\r\n    }\r\n\r\n    public static void main(String[] args) {<br>\r\n        int result = add(10, 20);<br>\r\n        System.out.println(\"Sum: \" + result);\r\n    }\r\n}<br><br>\r\nOutput:\r\n<br>\r\nSum: 30<br><br>\r\nC. Static vs. Non-Static Methods<br><br>\r\n1. Static Methods<br><br>\r\nDeclared using static keyword.\r\n<br>\r\nCan be called without creating an object of the class.\r\n<br>\r\nclass StaticExample {<br>\r\n    static void display() {<br>\r\n        System.out.println(\"Static Method Called\");\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        display(); // No need for an object<br>\r\n    }\r\n}<br><br>\r\n2. Non-Static Methods<br>\r\nRequire an object to be called.<br>\r\n\r\n<br><br>\r\nclass NonStaticExample {<br>\r\n    void show() {<br>\r\n        System.out.println(\"Non-Static Method Called\");<br>\r\n    }\r\n\r\n    public static void main(String[] args) {<br>\r\n        NonStaticExample obj = new NonStaticExample();<br><br>\r\n        obj.show(); // Object required\r\n    }\r\n}<br><br>\r\n4. Method Parameters and Return Types<br><br>\r\nA. Method with Parameters<br>\r\n<br>\r\npublic class User {<br>\r\n    public static void greet(String name) {<br>\r\n        System.out.println(\"Hello, \" + name);\r\n    }\r\n<br>\r\n    public static void main(String[] args) {<br>\r\n        greet(\"Raj\");<br>\r\n    }\r\n}\r\nOutput:\r\n<br>\r\nHello, Raj<br><br>\r\nB. Method Returning a Value<br>\r\npublic class Multiply {<br>\r\n    public static int multiply(int a, int b) {<br>\r\n        return a * b;<br>\r\n    }\r\n\r\n    public static void main(String[] args) {<br>\r\n        int result = multiply(5, 4);<br>\r\n        System.out.println(\"Product: \" + result);\r\n    }\r\n}\r\nOutput:\r\n<br>\r\nProduct: 20\r\n5. Method Overloading\r\nMultiple methods with the same name but different parameters.\r\n\r\n<br>\r\npublic class OverloadingExample {<br>\r\n    static int add(int a, int b) {<br>\r\n        return a + b;<br>\r\n    }\r\n\r\n    static double add(double a, double b) {<br>\r\n        return a + b;<br>\r\n    }\r\n\r\n    public static void main(String[] args) {<br>\r\n        System.out.println(add(5, 10));       // Calls int version<br>\r\n        System.out.println(add(5.5, 2.5));   // Calls double version\r\n    }\r\n}<br>\r\nOutput:\r\n<br>\r\n15<br>\r\n8.0<br><br>\r\n6. Method Overriding<br>\r\nA child class provides a different implementation of a parent class method.<br>\r\n\r\nclass Parent {<br>\r\n    void show() {<br>\r\n        System.out.println(\"Parent Method\");\r\n    }\r\n}\r\n<br>\r\nclass Child extends Parent {<br>\r\n    @Override<br>\r\n    void show() {<br>\r\n        System.out.println(\"Child Method\");\r\n    }\r\n}\r\n<br>\r\npublic class OverrideExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        Parent obj = new Child();<br>\r\n        obj.show();  // Calls overridden method in Child class\r\n    }\r\n}<br><br>\r\nOutput:<br>\r\n\r\nChild Method<br><br>\r\n7. Recursive Methods:\r\nA method that calls itself is recursive.\r\n<br>\r\npublic class RecursionExample {<br>\r\n    static int factorial(int n) {<br>\r\n        if (n == 0) return 1;<br>\r\n        return n * factorial(n - 1);<br>\r\n    }\r\n<br>\r\n    public static void main(String[] args) {<br>\r\n        System.out.println(factorial(5)); // 5 * 4 * 3 * 2 * 1 = 120\r\n    }\r\n}<br><br>\r\nOutput:\r\n<br>\r\n\r\n120\r\n\r\n<br><br>\r\nmethods with description \r\nStatic Method : Called without an object<br>\r\nNon-Static Method :	Requires an object to be called<br>\r\nMethod Overloading :	Same method name, different parameters<br>\r\nMethod Overriding :	Child class modifies parent method<br>\r\nRecursive Method :	Calls itself<br>\r\n<br><br>\r\n\r\n 1. Basic String Methods<br>\r\nThese methods help with fundamental string operations.\r\n<br><br>\r\nlength() : Returns the number of characters in a string.<br>\r\ncharAt(int index):\r\nGets the character at a specific index (0-based).<br>\r\nsubstring(int beginIndex, int endIndex):\r\nExtracts a substring from the string.<br>\r\ntoLowerCase() / toUpperCase():\r\nConverts a string to lowercase or uppercase.<br>\r\n<br>\r\n2. String Comparison & Searching<br><br>\r\nequals(String anotherString):\r\nCompares two strings for exact equality (case-sensitive).<br>\r\nequalsIgnoreCase(String anotherString):\r\nCompares two strings, ignoring case.<br>\r\ncompareTo(String anotherString):\r\nLexicographically compares two strings.<br>\r\ncontains(CharSequence sequence):\r\nChecks if a string contains a specific sequence.<br>\r\nstartsWith(String prefix) / endsWith(String suffix):\r\nChecks whether a string starts or ends with a specific substring.<br>\r\nindexOf(String str) / lastIndexOf(String str):\r\nFinds the index of the first or last occurrence of a substring.<br><br>\r\n\r\n3. String Modification<br><br>\r\nconcat(String str):\r\nJoins two strings.\r\n\r\n<br><br>\r\nreplace(char oldChar, char newChar):\r\nReplaces characters in a string.\r\n\r\n<br><br>\r\nreplaceAll(String regex, String replacement):\r\nReplaces all occurrences based on a regular expression.\r\n<br><br>\r\nSystem.out.println(\"123-456-789\".replaceAll(\"\\\\d\", \"*\")); // Output: \"***-***-***\"<br><br>\r\ntrim()<br><br>\r\nRemoves leading and trailing spaces.<br><br>\r\nSystem.out.println(\"  Java  \".trim()); // Output: \"Java\"<br><br>\r\n4. String Splitting & Joining : Splits a string into an array using a regex.<br>\r\n* split(String regex)\r\n\r\n<br><br>\r\n\r\njoin(CharSequence delimiter, CharSequence... elements)<br>\r\nJoins multiple strings with a delimiter.\r\n<br><br>\r\n\r\n5. String Conversion<br>\r\nvalueOf(Object obj)<br>\r\nConverts an object to a string.\r\n<br><br>\r\ngetBytes()<br><br>\r\nConverts a string into a byte array.<br>\r\n<br><br>\r\n\r\ntoCharArray()<br>\r\nConverts a string into a character array.<br>\r\n<br>\r\n\r\n 6. String Formatting<br><br>\r\n* format(String format, Object... args)<br>\r\nFormats a string using placeholders.<br>\r\n\r\n<br><br>7. StringBuilder vs StringBuffer<br><br>\r\nFor mutable string operations, use StringBuilder (faster, non-thread-safe) or StringBuffer (thread-safe).\r\n<br>\r\nStringBuilder Example:<br><br>\r\nStringBuilder sb = new StringBuilder(\"Hello\");<br>\r\nsb.append(\" World\");<br>\r\nSystem.out.println(sb.toString()); // Output: \"Hello World\"'),
(11, 'Introduction to OOP', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/j_IY76AdkGY?si=h64-MxsPeQU7226A\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'What is Object-Oriented Programming ?<br><br>\r\n\r\nObject-Oriented Programming (OOP) is a programming paradigm that organizes software design around objects rather than functions or logic. It allows us to structure programs using classes and objects, making code reusable, scalable, and easier to maintain.<br><br>\r\n\r\n1. Key Concepts of OOP<br>\r\nOOP is based on four core principles:<br>\r\n<br>\r\n1. Encapsulation (Data Hiding)<br>\r\nDefinition: Encapsulation is the concept of hiding the internal details of an object and exposing only the necessary parts.<br><br>\r\n\r\nAchieved using: private variables + public getter & setter methods.<br><br>\r\n\r\nWhy use Encapsulation? <br> \r\n-Protects data from unauthorized access<br>\r\n-Improves security and flexibility<br><br>\r\n\r\n2. Inheritance (Code Reusability)<br>\r\nDefinition: Inheritance allows a class (child class) to inherit attributes and methods from another class (parent class).<br><br>\r\n\r\nAchieved using: extends keyword.<br><br>\r\n\r\nWhy use Inheritance?<br> \r\nPromotes code reuse and reduces duplication<br>\r\nImproves maintainability<br><br>\r\n\r\n3. Polymorphism (Multiple Forms)<br>\r\nDefinition: The ability of an object to take many formsâa single method behaves differently depending on the object calling it.<br><br>\r\n\r\nTypes:<br>\r\ni. Method Overloading (Compile-time polymorphism) â Same method name, different parameters.<br>\r\nii. Method Overriding (Runtime polymorphism) â Child class redefines a method from the parent class.<br>\r\n\r\nWhy use Polymorphism?<br>\r\nImproves flexibility and scalability\r\n<br> Makes code more dynamic<br><br>\r\n\r\n4. Abstraction (Hiding Implementation)<br>\r\nDefinition: Abstraction is the concept of hiding implementation details and only exposing the necessary functionality.<br>\r\n\r\nAchieved using:<br>\r\ni. Abstract Class (abstract keyword)<br>\r\nii. Interface (interface keyword)<br><br>\r\n\r\nWhy use Abstraction? <br>\r\nIncreases security (hides unnecessary details)<br>\r\nEnhances flexibility and maintainability<br><br><br>\r\n\r\n2. Key Benefits of OOP<br>\r\n* Modularity â Code is organized into reusable components (objects).<br>\r\n* Reusability â Inheritance allows reuse of existing code.<br>\r\n* Flexibility â Polymorphism allows for easy extension of code.<br>\r\n* Security â Encapsulation hides sensitive data.<br>\r\n* Maintainability â Code is easier to modify and scale.<br>\r\n\r\n3. OOP in Java â Real-Life Example<br>\r\nBank System Example<br>\r\n\r\n// Abstract class<br>\r\nabstract class BankAccount {<br>\r\n    protected double balance;\r\n<br>\r\n    public BankAccount(double balance) {<br>\r\n        this.balance = balance;\r\n    }<br>\r\n\r\n    abstract void withdraw(double amount);<br>\r\n\r\n    public void deposit(double amount) {<br>\r\n        balance += amount;<br>\r\n        System.out.println(\"Deposited: \" + amount);<br>\r\n    }\r\n\r\n    public double getBalance() {<br>\r\n        return balance;\r\n    }\r\n}\r\n\r\n// Subclass (Inheritance + Method Overriding)<br>\r\nclass SavingsAccount extends BankAccount {<br>\r\n    public SavingsAccount(double balance) {<br>\r\n        super(balance);<br>\r\n    }\r\n\r\n    @Override<br>\r\n    public void withdraw(double amount) {<br>\r\n        if (balance >= amount) {<br>\r\n            balance -= amount;<br>\r\n            System.out.println(\"Withdrawn: \" + amount);<br>\r\n        } else {<br>\r\n            System.out.println(\"Insufficient balance\");\r\n        }\r\n    }\r\n}\r\n\r\npublic class Main {<br>\r\n    public static void main(String[] args) {<br>\r\n        SavingsAccount acc = new SavingsAccount(1000);<br>\r\n        acc.deposit(500);<br>\r\n        acc.withdraw(300);<br>\r\n        System.out.println(\"Final Balance: \" + acc.getBalance());\r\n    }\r\n}<br><br>\r\n Concepts Used:<br>\r\n Encapsulation (private balance, public getter/setter)<br>\r\n Inheritance (SavingsAccount extends BankAccount)<br>\r\n Abstraction (BankAccount as an abstract class)<br>\r\n Polymorphism (Overriding withdraw method)<br><br>\r\n\r\nSummary<br>\r\n Encapsulation ? Hides data<br>\r\n Inheritance ? Reuses code<br>\r\n Polymorphism ? One interface, multiple implementations<br>\r\n Abstraction ? Hides unnecessary details<br>'),
(12, 'Classes and Objects', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/Qg3HDbmbW6I?si=Q6MIO2baMH1aYIKO\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'Java OOPs Masterclass: Classes, Objects & Methods'),
(13, 'Constructors in Java', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/uCAaTvO7dn0?si=t9Aq4D0xm1kZGZCi\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'Constructors in Java<br>\r\nA constructor in Java is a special type of method that is used to initialize objects. It is automatically called when an object of a class is created.<br>\r\n<br>\r\nKey Characteristics of a Constructor:<br>\r\ni. Same Name as Class â The constructor must have the same name as the class.<br>\r\nii. No Return Type â Unlike methods, constructors do not have a return type (not even void).<br>\r\niii. Called Automatically â The constructor is executed when an object is created using new.<br>\r\niv. Used for Initialization â It helps assign initial values to instance variables.<br><br>\r\n\r\nTypes of Constructors in Java<br>\r\nJava provides three types of constructors:<br><br>\r\n\r\n1. Default Constructor (No-Arg Constructor)<br>\r\nIf no constructor is defined in a class, Java provides a default constructor automatically.<br>\r\n\r\nIt initializes the object with default values (0 for numbers, null for objects, false for booleans).<br>\r\n\r\nclass Car {<br>\r\n    String brand;<br>\r\n\r\n    // Default constructor<br>\r\n    Car() {<br>\r\n        System.out.println(\"Default Constructor Called!\");<br>\r\n        brand = \"Unknown\";\r\n    }<br>\r\n\r\n    void display() {<br>\r\n        System.out.println(\"Brand: \" + brand);\r\n    }\r\n}<br>\r\n\r\npublic class Main {<br>\r\n    public static void main(String[] args) {<br>\r\n        Car c = new Car(); // Default constructor is called<br>\r\n        c.display();\r\n    }\r\n}<br>\r\nOutput:<br>\r\n\r\nDefault Constructor Called!<br>\r\nBrand: Unknown<br>\r\n2. Parameterized Constructor<br>\r\nAccepts arguments to initialize object properties dynamically.<br>\r\n\r\nclass Car {<br>\r\n    String brand;<br>\r\n\r\n    // Parameterized constructor<br>\r\n    Car(String b) {<br>\r\n        brand = b;\r\n    }<br>\r\n\r\n    void display() {<br>\r\n        System.out.println(\"Brand: \" + brand);\r\n    }\r\n}<br>\r\n\r\npublic class Main {<br>\r\n    public static void main(String[] args) {<br>\r\n        Car car1 = new Car(\"Toyota\");<br>\r\n        Car car2 = new Car(\"Honda\");<br>\r\n\r\n        car1.display(); // Output: Brand: Toyota<br>\r\n        car2.display(); // Output: Brand: Honda\r\n    }\r\n}<br><br>\r\n3. Copy Constructor (User-Defined Copying)<br>\r\nUsed to create a copy of an existing object.<br>\r\n\r\nclass Car {<br>\r\n    String brand;<br>\r\n\r\n    // Parameterized constructor<br>\r\n    Car(String b) {<br>\r\n        brand = b;\r\n    }<br>\r\n\r\n    // Copy constructor<br>\r\n    Car(Car c) {<br>\r\n        this.brand = c.brand;<br>\r\n    }\r\n\r\n    void display() {<br>\r\n        System.out.println(\"Brand: \" + brand);\r\n    }\r\n}\r\n<br>\r\npublic class Main {<br>\r\n    public static void main(String[] args) {<br>\r\n        Car car1 = new Car(\"Tesla\");<br>\r\n        Car car2 = new Car(car1); // Copy constructor used<br>\r\n\r\n        car1.display(); // Output: Brand: Tesla<br>\r\n        car2.display(); // Output: Brand: Tesla\r\n    }\r\n}<br><br>\r\nConstructor Overloading in Java<br>\r\nJava allows multiple constructors in the same class with different parameters (overloading).\r\n<br>\r\nclass Car {<br>\r\n    String brand;<br>\r\n    int speed;<br>\r\n\r\n    // Default constructor<br>\r\n    Car() {<br>\r\n        brand = \"Unknown\";<br>\r\n        speed = 0;\r\n    }\r\n\r\n    // Parameterized constructor<br>\r\n    Car(String b, int s) {<br>\r\n        brand = b;<br>\r\n        speed = s;\r\n    }\r\n\r\n    void display() {<br>\r\n        System.out.println(\"Brand: \" + brand + \", Speed: \" + speed);\r\n    }\r\n}\r\n\r\npublic class Main {<br>\r\n    public static void main(String[] args) {<br>\r\n        Car car1 = new Car(); // Calls default constructor<br>\r\n        Car car2 = new Car(\"BMW\", 200); // Calls parameterized constructor<br>\r\n\r\n        car1.display(); // Output: Brand: Unknown, Speed: 0<br>\r\n        car2.display(); // Output: Brand: BMW, Speed: 200\r\n    }\r\n}\r\nUsing this() to Call Another Constructor<br>\r\nThe this() keyword can be used to call another constructor in the same class.<br>\r\n\r\nclass Car {<br>\r\n    String brand;<br>\r\n    int speed;<br>\r\n\r\n    // Default constructor<br>\r\n    Car() {<br>\r\n        this(\"Unknown\", 0); // Calls the parameterized constructor\r\n    }<br>\r\n\r\n    // Parameterized constructor<br>\r\n    Car(String b, int s) {<br>\r\n        brand = b;<br>\r\n        speed = s;\r\n    }\r\n\r\n    void display() {<br>\r\n        System.out.println(\"Brand: \" + brand + \", Speed: \" + speed);\r\n    }\r\n}\r\n\r\npublic class Main {<br>\r\n    public static void main(String[] args) {<br>\r\n        Car car1 = new Car(); // Calls default constructor, which calls <br>parameterized constructor<br>\r\n        car1.display(); // Output: Brand: Unknown, Speed: 0\r\n    }\r\n}');
INSERT INTO `video` (`V_id`, `V_Title`, `V_Url`, `V_Remarks`) VALUES
(14, 'Inheritance and Polymorphism', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/ST5PVeTixps?si=eiQsi07HdCGNJ_zP\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n', 'Polymorphism in Java<br>\r\n\r\nPolymorphism allows objects to be accessed through a common interface while behaving differently based on their specific implementations.<br><br>\r\n\r\nTypes of Polymorphism<br>\r\nCompile-time (Method Overloading)\r\n<br>\r\nRuntime (Method Overriding)\r\n<br>\r\nMethod Overloading (Compile-Time Polymorphism)<br>\r\nIt allows multiple methods in the same class with the same name but different parameters.\r\n<br><br>\r\nclass MathOperations {<br>\r\n    int add(int a, int b) {<br>\r\n        return a + b;\r\n    }\r\n    <br>\r\n    int add(int a, int b, int c) {<br>\r\n        return a + b + c;\r\n    }\r\n}<br><br>\r\n\r\npublic class OverloadingExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        MathOperations obj = new MathOperations();<br>\r\n        System.out.println(obj.add(5, 10));       // Calls first method<br>\r\n        System.out.println(obj.add(5, 10, 15));   // Calls second method\r\n    }\r\n}<br><br>\r\nMethod Overriding (Runtime Polymorphism)<br>\r\nIt occurs when a subclass provides a specific implementation of a method that is already defined in the parent class.<br>\r\n\r\nclass Animal {<br>\r\n    void makeSound() {<br>\r\n        System.out.println(\"Animal makes a sound\");\r\n    }\r\n}<br>\r\n\r\nclass Dog extends Animal {<br>\r\n    @Override<br>\r\n    void makeSound() {<br>\r\n        System.out.println(\"Dog barks\");\r\n    }\r\n}<br>\r\npublic class OverridingExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        Animal myAnimal = new Dog(); // Upcasting<br>\r\n        myAnimal.makeSound(); // Calls Dog\'s version\r\n    }\r\n}<br><br>\r\n\r\n3. Dynamic Method Dispatch (Runtime Polymorphism)<br>\r\nDynamic Method Dispatch (also known as late binding) occurs when a superclass reference variable holds a subclass object and calls an overridden method.\r\n<br><br>\r\nclass Parent {<br>\r\n    void show() {<br>\r\n        System.out.println(\"Parent class method\");\r\n    }\r\n}\r\n<br>\r\nclass Child extends Parent {<br>\r\n    @Override<br>\r\n    void show() {<br>\r\n        System.out.println(\"Child class method\");\r\n    }\r\n}\r\n<br>\r\npublic class DynamicDispatch {<br>\r\n    public static void main(String[] args) {<br>\r\n        Parent obj = new Child(); // Upcasting<br>\r\n        obj.show(); // Calls Child\'s show() method at runtime\r\n    }\r\n}<br>\r\n4. Real-World Example of Inheritance & Polymorphism<br>\r\nConsider a Banking System, where different account types override the calculateInterest() method.\r\n<br><br>\r\nclass BankAccount {<br>\r\n    void calculateInterest() {<br>\r\n        System.out.println(\"General Interest Calculation\");\r\n    }\r\n}\r\n<br>\r\nclass SavingsAccount extends BankAccount {<br>\r\n    @Override<br>\r\n    void calculateInterest() {<br>\r\n        System.out.println(\"Savings Account Interest Calculation\");\r\n    }\r\n}<br>\r\n\r\nclass FixedDepositAccount extends BankAccount {<br>\r\n    @Override<br>\r\n    void calculateInterest() {<br>\r\n        System.out.println(\"Fixed Deposit Interest Calculation\");\r\n    }\r\n}<br>\r\n\r\npublic class BankExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        BankAccount acc1 = new SavingsAccount();<br>\r\n        BankAccount acc2 = new FixedDepositAccount();<br>\r\n\r\n        acc1.calculateInterest(); // Calls SavingsAccount\'s method<br>\r\n        acc2.calculateInterest(); // Calls FixedDepositAccount\'s method\r\n    }\r\n}<br><br>\r\nshort description :<br>\r\n\r\nPolymorphism allows one interface to be used for multiple implementations, improving flexibility and scalability.\r\n<br>\r\nMethod Overloading is an example of Compile-Time Polymorphism.\r\n<br>\r\nMethod Overriding and Dynamic Method Dispatch demonstrate Runtime Polymorphism.'),
(15, 'Inheritance ', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/RNg4pjN3Fc0?si=bNTEnpd7UmbH1kZO\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'Inheritance in Java<br>\r\nInheritance is one of the key features of Object-Oriented Programming (OOP) that allows a class (child/subclass) to inherit the properties and behaviors (fields and methods) of another class (parent/superclass). It promotes code reusability and establishes a hierarchical relationship between classes.<br><br>\r\n\r\nTypes of Inheritance in Java<br>\r\nJava supports the following types of inheritance:\r\n<br><br>\r\n1. Single Inheritance<br>\r\nIn single inheritance, a subclass inherits from a single superclass. This is the most basic form of inheritance.<br><br>\r\n\r\nExample:\r\n<br><br>\r\nclass Parent {<br>\r\n    void display() {<br>\r\n        System.out.println(\"This is the Parent class.\");\r\n    }\r\n}<br>\r\n\r\nclass Child extends Parent {<br>\r\n    void show() {<br>\r\n        System.out.println(\"This is the Child class.\");\r\n    }\r\n}\r\n<br>\r\npublic class Main {<br>\r\n    public static void main(String[] args) {<br>\r\n        Child obj = new Child();<br>\r\n        obj.display();  // Inherited method<br>\r\n        obj.show();     // Child\'s own method\r\n    }\r\n}<br>\r\n2. Multilevel Inheritance<br>\r\nIn multilevel inheritance, a class inherits from another class, which in turn inherits from a third class, forming a chain.\r\n<br><br>\r\nExample:<br>\r\n\r\nclass Grandparent {<br>\r\n    void greet() {<br>\r\n        System.out.println(\"Hello from Grandparent\");\r\n    }\r\n}<br>\r\n\r\nclass Parent extends Grandparent {<br>\r\n    void display() {<br>\r\n        System.out.println(\"Hello from Parent\");\r\n    }\r\n}\r\n<br>\r\nclass Child extends Parent {<br>\r\n    void show() {<br>\r\n        System.out.println(\"Hello from Child\");\r\n    }\r\n}<br>\r\n\r\npublic class Main {<br>\r\n    public static void main(String[] args) {<br>\r\n        Child obj = new Child();<br>\r\n        obj.greet();<br>\r\n        obj.display();<br>\r\n        obj.show();\r\n    }\r\n}<br>\r\n3. Hierarchical Inheritance<br>\r\nIn hierarchical inheritance, multiple child classes inherit from a single parent class.\r\n<br>\r\nExample:\r\n<br>\r\nclass Parent {<br>\r\n    void message()<br> {\r\n        System.out.println(\"Message from Parent class.\");\r\n    }\r\n}<br>\r\n\r\nclass Child1 extends Parent {<br>\r\n    void display() {<br>\r\n        System.out.println(\"Child1 extending Parent.\");\r\n    }\r\n}\r\n<br>\r\nclass Child2 extends Parent {<br>\r\n    void show() {<br>\r\n        System.out.println(\"Child2 extending Parent.\");\r\n    }\r\n}<br>\r\n\r\npublic class Main {<br>\r\n    public static void main(String[] args) {<br>\r\n        Child1 obj1 = new Child1();<br>\r\n        obj1.message();<br>\r\n        obj1.display();<br><br>\r\n        \r\n        Child2 obj2 = new Child2();<br>\r\n        obj2.message();<br>\r\n        obj2.show();\r\n    }\r\n}<br><br>\r\n4. Multiple Inheritance (via Interfaces)<br>\r\nJava does not support multiple inheritance with classes to avoid ambiguity issues. However, it allows multiple inheritance through interfaces.<br>\r\n<br>\r\nExample:\r\n<br>\r\ninterface A {<br>\r\n    void methodA();\r\n}<br>\r\n\r\ninterface B {<br>\r\n    void methodB();\r\n}<br>\r\n\r\nclass C implements A, B {<br>\r\n    public void methodA() {<br>\r\n        System.out.println(\"Implementing methodA from Interface A\");\r\n    }<br>\r\n\r\n    public void methodB() {<br>\r\n        System.out.println(\"Implementing methodB from Interface B\");\r\n    }\r\n}\r\n<br>\r\npublic class Main {<br>\r\n    public static void main(String[] args) {<br>\r\n        C obj = new C();<br>\r\n        obj.methodA();<br>\r\n        obj.methodB();\r\n    }\r\n}'),
(16, 'Polymorphism', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/TRlz0X5hD7E?si=7VGNmhWOOWBX7MU7\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/NiqDfdVhhPM?si=88q0po3mRe3hTeeL\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', 'Polymorphism<br><br>\r\n\r\nPolymorphism in Java is categorized into Compile-Time Polymorphism and Run-Time Polymorphism.<br><br>\r\n\r\n1. Compile-Time Polymorphism (Method Overloading)<br>\r\nOccurs when multiple methods have the same name but different parameters.\r\n\r\nThe method to be called is resolved at compile time.\r\n\r\nAchieved through method overloading.\r\n<br>\r\nExample of Method Overloading\r\n<br>\r\nclass MathOperations {<br>\r\n    // Overloaded add() method<br>\r\n    int add(int a, int b) {<br>\r\n        return a + b;\r\n    }\r\n    <br>\r\n    double add(double a, double b) {<br>\r\n        return a + b;\r\n    }\r\n}\r\n<br>\r\npublic class TestOverloading {<br>\r\n    public static void main(String[] args) {<br>\r\n        MathOperations obj = new MathOperations();<br>\r\n        System.out.println(obj.add(5, 10));       // Calls add(int, int)<br>\r\n        System.out.println(obj.add(5.5, 2.2));   // Calls add(double, double)\r\n    }\r\n}<br><br>\r\nKey Points:<br>\r\n\r\nThe method signature (name + parameters) determines which method is invoked.\r\n\r\nIt improves readability and code organization.\r\n<br><br>\r\n2. Run-Time Polymorphism (Method Overriding)<br>\r\nOccurs when a subclass provides a specific implementation for a method declared in its superclass.\r\n\r\nThe method to be executed is determined at runtime.\r\n\r\nAchieved through method overriding.\r\n<br><br>\r\nExample of Method Overriding\r\n<br>\r\nclass Animal {<br>\r\n    void makeSound() {<br>\r\n        System.out.println(\"Animal makes a sound\");\r\n    }\r\n}\r\n<br>\r\nclass Dog extends Animal {<br>\r\n    @Override<br>\r\n    void makeSound() {<br>\r\n        System.out.println(\"Dog barks\");\r\n    }\r\n}\r\n<br>\r\npublic class TestOverriding {<br>\r\n    public static void main(String[] args) {<br>\r\n        Animal myAnimal = new Dog();  // Upcasting<br>\r\n        myAnimal.makeSound();  // Calls Dog\'s makeSound() at runtime\r\n    }\r\n}<br><br>\r\nKey Points:\r\n<br>\r\nThe method signature remains the same, but the implementation differs.\r\n\r\n@Override annotation is used for clarity.\r\n\r\nDynamic method dispatch ensures the correct method is called based on the object\'s runtime type.'),
(17, 'Encapsulation and Abstraction', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/ifJ0eCrEC44?si=CXEqW5eyrCAbga1M\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/W0Qv4UkCo6k?si=Z_SehZCdqeUPMpWT\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', '1. Encapsulation in Java | 2. Abstraction in Java\r\n\r\nEncapsulation in Java<br><br>\r\nEncapsulation is one of the fundamental principles of Object-Oriented Programming (OOP) in Java. It refers to the bundling of data (variables) and methods (functions) that operate on the data into a single unit, i.e., a class. The key idea behind encapsulation is to restrict direct access to some of an object\'s components, making the code more secure and maintainable.\r\n<br><br>\r\nKey Features of Encapsulation:<br>\r\nData Hiding: Instance variables are kept private to prevent direct access from outside the class.<br>\r\n\r\nControlled Access: Public getter and setter methods provide controlled access to the private data.<br>\r\n\r\nIncreased Maintainability: Changes to data can be managed centrally, reducing code dependencies.\r\n<br>\r\nBetter Modularity: Encapsulation promotes modular code, improving reusability and debugging.\r\n<br><br>\r\nExample of Encapsulation:<br>\r\n<br>\r\nclass Person {<br>\r\n    private String name;<br>\r\n    private int age;<br>\r\n\r\n    // Constructor<br>\r\n    public Person(String name, int age) {<br>\r\n        this.name = name;<br>\r\n        this.age = age;\r\n    }<br>\r\n\r\n    // Getter method<br>\r\n    public String getName() {<br>\r\n        return name;\r\n    }<br>\r\n\r\n    // Setter method<br>\r\n    public void setName(String name) {<br>\r\n        this.name = name;\r\n    }<br>\r\n\r\n    public int getAge() {<br>\r\n        return age;\r\n    }<br>\r\n\r\n    public void setAge(int age) {<br>\r\n        if (age > 0) {<br>\r\n            this.age = age;\r\n        <br>} else {\r\n            System.out.println(\"Age must be positive.\");\r\n        }\r\n    }\r\n}<br>\r\n\r\npublic class EncapsulationDemo {<br>\r\n    public static void main(String[] args) {<br>\r\n        Person p = new Person(\"John\", 25);<br>\r\n        System.out.println(\"Name: \" + p.getName());<br>\r\n        System.out.println(\"Age: \" + p.getAge());<br>\r\n\r\n        // Updating values using setter methods<br>\r\n        p.setName(\"Alice\");<br>\r\n        p.setAge(30);<br>\r\n        System.out.println(\"Updated Name: \" + p.getName());<br>\r\n        System.out.println(\"Updated Age: \" + p.getAge());\r\n    }\r\n}<br><br>\r\nOutput:\r\n<br>\r\nName: John<br>\r\nAge: 25<br>\r\nUpdated Name: Alice<br>\r\nUpdated Age: 30<br><br>\r\nAbstraction in Java<br>\r\nAbstraction is another key concept of OOP that focuses on hiding implementation details and showing only the necessary functionalities. It allows programmers to define a blueprint for objects without specifying how the functionalities are implemented.<br>\r\n<br>\r\nWays to Achieve Abstraction in Java:<br>\r\nAbstract Classes: Declared using the abstract keyword, they can have abstract methods (without implementation) and concrete methods (with implementation).\r\n<br><br>\r\nInterfaces: <br>They define a contract that classes must follow, ensuring a common structure while allowing multiple inheritance.\r\n<br><br>\r\nExample of Abstraction using an Abstract Class:\r\n<br>\r\nabstract class Vehicle {<br>\r\n    abstract void start(); // Abstract method<br>\r\n\r\n    public void stop() {<br>\r\n        System.out.println(\"Vehicle is stopping.\");\r\n    }\r\n}\r\n<br>\r\nclass Car extends Vehicle {<br>\r\n    @Override<br>\r\n    void start() {<br>\r\n        System.out.println(\"Car is starting with a key.\");\r\n    }\r\n}\r\n<br>\r\npublic class AbstractionDemo {<br>\r\n    public static void main(String[] args) {<br>\r\n        Vehicle myCar = new Car();<br>\r\n        myCar.start();<br>\r\n        myCar.stop();\r\n    }\r\n}<br><br>\r\nOutput:\r\n<br>\r\nCar is starting with a key.<br>\r\nVehicle is stopping.<br><br>\r\nExample of Abstraction using an Interface:\r\n<br><br>\r\ninterface Animal {<br>\r\n    void makeSound(); // Abstract method (by default public and abstract)\r\n}\r\n<br>\r\nclass Dog implements Animal {<br>\r\n    @Override<br>\r\n    public void makeSound() {<br>\r\n        System.out.println(\"Dog barks.\");\r\n    }\r\n}\r\n<br>\r\npublic class InterfaceDemo {<br>\r\n    public static void main(String[] args) {<br>\r\n        Animal myDog = new Dog();<br>\r\n        myDog.makeSound();\r\n    }\r\n}<br><br>\r\nOutput:\r\n<br>\r\nDog barks.'),
(18, 'Exception handling', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/IZu5rZTN7PI?si=ellS7hHIebNPqiwQ\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/3N5Js9k3tm4?si=JLHXfpwq5O6foE6L\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', '\r\nExceptions in Java<br>\r\n1. What is an Exception?<br>\r\nAn exception is an event that disrupts the normal flow of the program. It occurs during runtime and can be handled using Javaâs exception-handling mechanisms.\r\n<br><br>\r\nTypes of Exceptions<br>\r\nChecked Exceptions â Exceptions that are checked at compile-time (e.g., IOException, SQLException).<br>\r\n\r\nUnchecked Exceptions â Exceptions that occur at runtime (e.g., NullPointerException, ArrayIndexOutOfBoundsException).<br>\r\n\r\nErrors â Critical issues that cannot be handled (e.g., OutOfMemoryError, StackOverflowError).<br><br>\r\n\r\n2. Exception Handling Keywords<br><br>\r\n2.1 try and catch<br>\r\nThe try block contains code that may throw an exception, and the catch block handles the exception.<br><br>\r\n\r\nExample: Handling an exception using try-catch\r\n<br>\r\npublic class TryCatchExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        try {<br>\r\n            int result = 10 / 0;  // This will throw ArithmeticException<br>\r\n        } catch (ArithmeticException e) {<br>\r\n            System.out.println(\"Exception caught: \" + e.getMessage());\r\n        }<br>\r\n        System.out.println(\"Program continues...\");\r\n    }\r\n}<br><br>\r\n2.2 finally<br>\r\nThe finally block contains code that executes whether an exception occurs or not.\r\n<br>\r\nExample: finally block execution\r\n<br>\r\npublic class FinallyExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        try {<br>\r\n            int data = 10 / 0;<br>\r\n        } catch (ArithmeticException e) {<br>\r\n            System.out.println(\"Exception caught.\");\r\n        } finally {<br>\r\n            System.out.println(\"Finally block executed.\");\r\n        }\r\n    }\r\n}<br><br>\r\n2.3 throw<br>\r\nThe throw keyword is used to explicitly throw an exception.\r\n<br>\r\nExample: Throwing an exception\r\n<br>\r\npublic class ThrowExample {<br>\r\n    static void checkAge(int age) {<br>\r\n        if (age < 18) {<br>\r\n            throw new ArithmeticException(\"Not eligible to vote\");<br>\r\n        } else {<br>\r\n            System.out.println(\"Eligible to vote\");\r\n        }\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        checkAge(16);  // This will throw an exception\r\n    }\r\n}<br><br>\r\n2.4 throws<br>\r\nThe throws keyword is used in method signatures to indicate that a method may throw an exception.\r\n<br><br>\r\nExample: Using throws\r\n<br><br>\r\nimport java.io.*;<br>\r\n\r\npublic class ThrowsExample {<br>\r\n    static void readFile() throws IOException {<br>\r\n        FileReader file = new FileReader(\"test.txt\");<br>\r\n        file.read();<br>\r\n        file.close();\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        try {<br>\r\n            readFile();<br>\r\n        } catch (IOException e) {<br>\r\n            System.out.println(\"Exception handled: \" + e.getMessage());\r\n        }\r\n    }\r\n}<br><br>\r\n2.5 try-with-resources (Automatic Resource Management)<br>\r\nIntroduced in Java 7, it ensures that resources like files, database connections, etc., are closed automatically.<br>\r\n<br>\r\nExample: Using try-with-resources\r\n<br>\r\nimport java.io.*;<br>\r\n\r\npublic class TryWithResourcesExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        try (BufferedReader br = new BufferedReader(new FileReader(\"test.txt\"))) {<br>\r\n            System.out.println(br.readLine());<br>\r\n        } catch (IOException e) {<br>\r\n            System.out.println(\"Exception handled: \" + e.getMessage());\r\n        }\r\n    }\r\n}<br><br>\r\n2.6 Custom Exception<br>\r\nYou can define your own exceptions by extending the Exception class.\r\n<br><br>\r\nExample: Creating and throwing a custom exception\r\n<br><br>\r\nclass InvalidAgeException extends Exception {<br>\r\n    public InvalidAgeException(String message) {<br>\r\n        super(message);\r\n    }\r\n}<br>\r\n\r\npublic class CustomExceptionExample {<br>\r\n    static void validateAge(int age) throws InvalidAgeException {<br>\r\n        if (age < 18) {<br>\r\n            throw new InvalidAgeException(\"Age must be 18 or above.\");<br>\r\n        } else {<br>\r\n            System.out.println(\"Valid age.\");\r\n        }\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        try {<br>\r\n            validateAge(16);<br>\r\n        } catch (InvalidAgeException e) {<br>\r\n            System.out.println(\"Caught Exception: \" + e.getMessage());\r\n        }\r\n    }\r\n}<br><br>\r\n\r\nJava Thread Lifecycle<br><br>\r\n1. Introduction to Threads<br>\r\nA thread is a lightweight process that executes independently. In Java, threads are used to perform concurrent execution of tasks, making programs more efficient.\r\n<br><br>\r\nJava provides two ways to create threads:\r\n<br>\r\nExtending the Thread class\r\n<br>\r\nImplementing the Runnable interface\r\n<br><br>\r\n2. Java Thread Lifecycle Stages<br>\r\nA Java thread goes through five states in its lifecycle:\r\n<br><br>\r\n\r\nNew	:The thread is created but not started.<br>\r\nRunnable:	The thread is ready to run but waiting for CPU time.<br>\r\nBlocked:	The thread is waiting for a resource.<br>\r\nWaiting	:The thread is waiting indefinitely for another thread to notify it.<br>\r\nTimed Waiting:	The thread is waiting for a specified time.<br>\r\nTerminated	:The thread has finished execution.<br><br>\r\n\r\n3. Thread Lifecycle in Detail<br><br>\r\n3.1 NEW (Created but not started)<br>\r\nA thread is in the NEW state when it is created using the Thread class but not started yet.\r\n<br>\r\nExample: Creating a Thread\r\n<br>\r\nclass MyThread extends Thread {<br>\r\n    public void run() {<br>\r\n        System.out.println(\"Thread is running...\");\r\n    }\r\n}\r\n<br>\r\npublic class ThreadNewState {<br>\r\n    public static void main(String[] args) {<br>\r\n        MyThread t = new MyThread();  // Thread created (NEW state)<br>\r\n        System.out.println(\"Thread created but not started.\");\r\n    }\r\n}<br><br>\r\n3.2 RUNNABLE (Waiting for CPU time)<br>\r\nWhen we call the start() method, the thread moves from NEW ? RUNNABLE. It is ready to run but waits for CPU scheduling.\r\n<br><br>\r\nExample: Thread in RUNNABLE state\r\n<br>\r\nclass MyThread extends Thread {<br>\r\n    public void run() {<br>\r\n        System.out.println(\"Thread is running...\");\r\n    }\r\n}<br>\r\n\r\npublic class RunnableStateExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        MyThread t = new MyThread();<br>\r\n        t.start();  // Now the thread is in RUNNABLE state<br>\r\n        System.out.println(\"Thread is ready to run.\");\r\n    }\r\n}<br><br>\r\n3.3 BLOCKED (Waiting for a resource)<br>\r\nA thread enters the BLOCKED state if it tries to access a synchronized resource that is already locked by another thread.<br>\r\n\r\nExample: Thread in BLOCKED state<br>\r\nclass SharedResource {<br>\r\n    synchronized void display() {<br>\r\n        System.out.println(Thread.currentThread().getName() + \" is executing.\");<br>\r\n        try { Thread.sleep(1000); } catch (InterruptedException e) {}\r\n    }\r\n}\r\n<br>\r\nclass MyThread extends Thread {<br>\r\n    SharedResource resource;<br>\r\n    \r\n    MyThread(SharedResource resource) {<br>\r\n        this.resource = resource;\r\n    }\r\n<br>\r\n    public void run() {<br>\r\n        resource.display();\r\n    }\r\n}\r\n<br>\r\npublic class BlockedStateExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        SharedResource obj = new SharedResource();<br>\r\n\r\n        MyThread t1 = new MyThread(obj);<br>\r\n        MyThread t2 = new MyThread(obj);<br>\r\n\r\n        t1.start();<br>\r\n        t2.start();  // t2 will be in BLOCKED state until t1 releases the lock\r\n    }\r\n}<br><br>\r\n3.4 WAITING (Waiting indefinitely for another thread)<br>\r\nA thread enters the WAITING state when it calls wait() and stays there until another thread calls notify().<br>\r\n\r\nExample: Thread in WAITING state\r\n<br>\r\nclass WaitNotifyExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        final Object lock = new Object();<br>\r\n        \r\n        Thread t1 = new Thread(() -> {<br>\r\n            synchronized (lock) {<br>\r\n                try {<br>\r\n                    System.out.println(\"Thread is waiting...\");<br>\r\n                    lock.wait();  // Moves to WAITING state<br>\r\n                    System.out.println(\"Thread resumed.\");<br>\r\n                } catch (InterruptedException e) {}\r\n            }\r\n        });<br>\r\n\r\n        Thread t2 = new Thread(() -> {<br>\r\n            try { Thread.sleep(2000); } catch (InterruptedException e) {}<br>\r\n            synchronized (lock) {<br>\r\n                lock.notify();  // Wakes up the waiting thread<br>\r\n                System.out.println(\"Thread notified.\");\r\n            }\r\n        });\r\n\r\n        t1.start();<br>\r\n        t2.start();\r\n    }\r\n}<br>\r\n3.5 TIMED_WAITING (Waiting for a fixed time)<br><br>\r\nA thread enters the TIMED_WAITING state when it calls sleep() or join() with a timeout.\r\n<br>\r\nExample: Thread in TIMED_WAITING state<br>\r\nclass TimedWaitingExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        Thread t = new Thread(() -> {<br>\r\n            try {<br>\r\n                System.out.println(\"Thread is sleeping...\");<br>\r\n                Thread.sleep(3000);  // TIMED_WAITING state<br>\r\n                System.out.println(\"Thread woke up.\");<br>\r\n            } catch (InterruptedException e) {}\r\n        });<br>\r\n\r\n        t.start();\r\n    }\r\n}<br><br>\r\n3.6 TERMINATED (Thread has finished execution)<br>\r\nA thread enters the TERMINATED state after completing its execution.\r\n<br>\r\nExample: Thread in TERMINATED state\r\n<br>\r\nclass MyThread extends Thread {<br>\r\n    public void run() {<br>\r\n        System.out.println(\"Thread is running...\");\r\n    }\r\n}<br>\r\n\r\npublic class TerminatedStateExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        MyThread t = new MyThread();<br>\r\n        t.start();<br>  \r\n        System.out.println(\"Thread has finished execution.\");\r\n    }\r\n}<br><br>\r\n4. Summary of Thread Methods<br><br>\r\nstart()	:Starts a new thread.<br>\r\nsleep(ms):	Makes the thread sleep for the specified time.<br>\r\nwait()	:Puts the thread in WAITING state until notify() is called.<br>\r\nnotify():	Wakes up a waiting thread.<br>\r\njoin()	:Waits for a thread to complete execution.'),
(19, 'Multithreading Programming', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/GdZLlPMt5ek?si=5GRH5xsyYfaWbMaH\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/wqJocu5yPY0?si=LyDyz4wLrWjYu85w\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', '1. Multithreading in Java | 2. Multithreading- by extending Thread class in java\r\n\r\nMultithreading in Java â Extending the Thread Class<br>\r\nJava provides a built-in Thread class that can be extended to create a new thread. This approach allows you to define a separate execution path for the program.\r\n<br>\r\nSteps to Create a Thread by Extending Thread Class\r\nExtend the Thread class.<br>\r\n\r\nOverride the run() method to define the thread\'s task.\r\n<br>\r\nCreate an instance of the subclass and start the thread using the start() method.\r\n<br><br>\r\nExample: Creating a Thread by Extending Thread Class\r\n<br>\r\n// Step 1: Extend the Thread class<br>\r\nclass MyThread extends Thread {<br>\r\n    // Step 2: Override the run() method<br>\r\n    public void run() {<br>\r\n        for (int i = 1; i <= 5; i++) {<br>\r\n            System.out.println(Thread.currentThread().getName() + \" - Value: \" + i);<br>\r\n            try {<br>\r\n                Thread.sleep(1000); // Pauses execution for 1 second\r\n            } catch (InterruptedException e) {<br>\r\n                System.out.println(e.getMessage());\r\n            }\r\n        }\r\n    }\r\n}\r\n<br>\r\npublic class ThreadExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        // Step 3: Create thread objects<br>\r\n        MyThread t1 = new MyThread();<br>\r\n        MyThread t2 = new MyThread();<br>\r\n\r\n        // Step 4: Start the threads<br>\r\n        t1.start();<br>\r\n        t2.start();\r\n    }\r\n}<br><br>\r\nExplanation:<br>\r\nMyThread extends Thread and overrides run(), which contains the logic to be executed in the thread.\r\n<br>\r\nstart() is called on the thread objects (t1 and t2), causing them to execute concurrently.\r\n<br>\r\nThread.sleep(1000) introduces a 1-second delay to simulate processing time.\r\n<br>\r\nOutput (Order May Vary Due to Concurrency):\r\n<br>\r\nThread-0 - Value: 1<br>\r\nThread-1 - Value: 1<br>\r\nThread-0 - Value: 2<br>\r\nThread-1 - Value: 2<br>\r\nThread-0 - Value: 3<br>\r\nThread-1 - Value: 3<br>\r\n...<br><br>\r\nKey Points:<br>\r\nEach thread runs independently.<br>\r\n\r\nThe start() method is used to begin execution; calling run() directly wonât start a new thread.<br>\r\n\r\nThe default thread names (Thread-0, Thread-1) can be customized using setName().'),
(20, 'File Handling ', '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/-YySZQcmhGk?si=YmAhJlk0O6k2yO4l\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/SslMi6ptwH8?si=Gyf3wraolqwLpCNg\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', '\r\nReading and Writing Files in Java<br><br>\r\nFile handling is an essential part of Java programming, allowing developers to read from and write to files efficiently. Java provides several classes for handling files, primarily found in the java.io and java.nio packages.\r\n<br>\r\n1. Writing to a File in Java<br><br>\r\nJava provides multiple ways to write to a file, including:\r\n<br>\r\nFileWriter\r\n<br>\r\nBufferedWriter\r\n<br>\r\nPrintWriter\r\n<br>\r\nFiles.write() (from java.nio.file)<br>\r\n<br>\r\nExample: Writing Using FileWriter<br>\r\nThe FileWriter class allows writing character data to a file.\r\n<br>\r\nimport java.io.FileWriter;<br>\r\nimport java.io.IOException;<br>\r\n\r\npublic class FileWriteExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        try (FileWriter writer = new FileWriter(\"output.txt\")) {<br>\r\n            writer.write(\"Hello, this is a test file!\");<br>\r\n            writer.write(\"\\nWriting to a file in Java.\");<br>\r\n            System.out.println(\"Successfully written to the file.\");<br>\r\n        } catch (IOException e) {<br>\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}<br><br>\r\nExample: Writing Using BufferedWriter<br>\r\nBufferedWriter improves performance by reducing disk I/O operations.<br>\r\n\r\nimport java.io.BufferedWriter;<br>\r\nimport java.io.FileWriter;<br>\r\nimport java.io.IOException;<br>\r\n\r\npublic class BufferedWriteExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        try (BufferedWriter writer = new BufferedWriter(new FileWriter(\"output.txt\"))) {<br>\r\n            writer.write(\"Buffered Writer Example\");<br>\r\n            writer.newLine();<br>\r\n            writer.write(\"This is another line.\");<br>\r\n            System.out.println(\"File written successfully.\");<br>\r\n        } catch (IOException e) {<br>\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}\r\n2. Reading from a File in Java<br>\r\nSimilar to writing, Java provides multiple ways to read files:\r\n<br>\r\nFileReader\r\n<br>\r\nBufferedReader\r\n<br>\r\nScanner\r\n<br>\r\nFiles.readAllLines() (from java.nio.file)\r\n<br>\r\nExample: Reading Using FileReader<br>\r\nThe FileReader class reads character files.\r\n<br>\r\nimport java.io.FileReader;<br>\r\nimport java.io.IOException;\r\n<br>\r\npublic class FileReadExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        try (FileReader reader = new FileReader(\"output.txt\")) {<br>\r\n            int character;<br>\r\n            while ((character = reader.read()) != -1) {<br>\r\n                System.out.print((char) character);\r\n            }<br>\r\n        } catch (IOException e) {<br>\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}<br><br>\r\nExample: Reading Using BufferedReader<br>\r\nBufferedReader is more efficient for reading large files.<br>\r\n\r\nimport java.io.BufferedReader;<br>\r\nimport java.io.FileReader;<br>\r\nimport java.io.IOException;\r\n<br>\r\npublic class BufferedReadExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        try (BufferedReader reader = new BufferedReader(new FileReader(\"output.txt\"))) {<br>\r\n            String line;<br>\r\n            while ((line = reader.readLine()) != null) {<br>\r\n                System.out.println(line);<br>\r\n            }\r\n        } catch (IOException e) {<br>\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}<br><br>\r\nExample: Reading Using Scanner<br>\r\nThe Scanner class allows more flexible input parsing.\r\n<br>\r\nimport java.io.File;<br>\r\nimport java.io.FileNotFoundException;<br>\r\nimport java.util.Scanner;<br>\r\n\r\npublic class ScannerReadExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        try (Scanner scanner = new Scanner(new File(\"output.txt\"))) {<br>\r\n            while (scanner.hasNextLine()) {<br>\r\n                System.out.println(scanner.nextLine());<br>\r\n            }\r\n        } catch (FileNotFoundException e) {<br>\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}<br>\r\n3. Writing and Reading Using NIO Package<br>\r\nThe java.nio.file.Files class provides methods for file operations.\r\n<br>\r\nWriting Using Files.write()\r\n<br>\r\nimport java.nio.file.Files;<br>\r\nimport java.nio.file.Paths;<br>\r\nimport java.io.IOException;<br>\r\nimport java.util.List;<br>\r\n\r\npublic class NIOWriteExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        String content = \"Hello, this is NIO file handling!\";<br>\r\n        try {<br>\r\n            Files.write(Paths.get(\"niofile.txt\"), content.getBytes());<br>\r\n            System.out.println(\"File written using NIO.\");<br>\r\n        } catch (IOException e) {<br>\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}<br>\r\nReading Using Files.readAllLines()\r\n<br>\r\nimport java.nio.file.Files;<br>\r\nimport java.nio.file.Paths;<br>\r\nimport java.io.IOException;<br>\r\nimport java.util.List;<br>\r\n\r\npublic class NIOReadExample {<br>\r\n    public static void main(String[] args) {<br>\r\n        try {<br>\r\n            List<String> lines = Files.readAllLines(Paths.get(\"niofile.txt\"));<br>\r\n            lines.forEach(System.out::println);<br>\r\n        } catch (IOException e) {<br>\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}'),
(21, 'Excercise', '', '\r\n\r\n1. Average of Three Numbers\r\n<br><br>\r\nimport java.util.Scanner;<br>\r\n\r\npublic class AverageCalculator {<br>\r\n    public static double average(int a, int b, int c) {<br>\r\n        return (a + b + c) / 3.0;\r\n    }\r\n<br>\r\n    public static void main(String[] args) {<br>\r\n        Scanner sc = new Scanner(System.in);<br>\r\n        System.out.print(\"Enter three numbers: \");<br>\r\n        int x = sc.nextInt(), y = sc.nextInt(), z = sc.nextInt();<br>\r\n        System.out.println(\"Average: \" + average(x, y, z));<br>\r\n        sc.close();\r\n    }\r\n}<br><br><\r\n2. Sum of Odd Numbers from 1 to N\r\n<br><br>\r\nimport java.util.Scanner;<br>\r\n\r\npublic class SumOddNumbers {<br>\r\n    public static int sumOdd(int n) {<br>\r\n        int sum = 0;<br>\r\n        for (int i = 1; i <= n; i += 2) {<br>\r\n            sum += i;\r\n        }<br>\r\n        return sum;\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        Scanner sc = new Scanner(System.in);<br>\r\n        System.out.print(\"Enter n: \");<br>\r\n        int n = sc.nextInt();<br>\r\n        System.out.println(\"Sum of odd numbers: \" + sumOdd(n));<br>\r\n        sc.close();\r\n    }\r\n}<br><br>\r\n3. Greater of Two Numbers<br><br>\r\n\r\nimport java.util.Scanner;<br>\r\n\r\npublic class GreaterNumber {<br>\r\n    public static int greater(int a, int b) {<br>\r\n        return (a > b) ? a : b;\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        Scanner sc = new Scanner(System.in);<br>\r\n        System.out.print(\"Enter two numbers: \");<br>\r\n        int x = sc.nextInt(), y = sc.nextInt();<br>\r\n        System.out.println(\"Greater number: \" + greater(x, y));<br>\r\n        sc.close();\r\n    }\r\n}<br><br>\r\n4. Circumference of a Circle\r\n<br><br>\r\nimport java.util.Scanner;<br>\r\n\r\npublic class CircleCircumference {<br>\r\n    public static double circumference(double radius) {<br>\r\n        return 2 * Math.PI * radius;\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        Scanner sc = new Scanner(System.in);<br>\r\n        System.out.print(\"Enter radius: \");<br>\r\n        double r = sc.nextDouble();<br>\r\n        System.out.println(\"Circumference: \" + circumference(r));<br>\r\n        sc.close();\r\n    }\r\n}<br><br>\r\n5. Voting Eligibility<br>\r\n<br>\r\nimport java.util.Scanner;<br>\r\n\r\npublic class VotingEligibility {<br>\r\n    public static boolean isEligible(int age) {<br>\r\n        return age >= 18;\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        Scanner sc = new Scanner(System.in);<br>\r\n        System.out.print(\"Enter age: \");<br>\r\n        int age = sc.nextInt();<br>\r\n        System.out.println(isEligible(age) ? \"Eligible to vote\" : \"Not eligible to vote\");<br>\r\n        sc.close();\r\n    }\r\n}<br><br>\r\n6. Infinite Loop using do-while\r\n<br><br>\r\npublic class InfiniteLoop {<br>\r\n    public static void main(String[] args) {<br>\r\n        do {<br>\r\n            System.out.println(\"This is an infinite loop\");<br>\r\n        } while (true);<br>\r\n    }\r\n}<br><br>\r\n7. Count of Positive, Negative, and Zeros\r\n<br><br>\r\nimport java.util.Scanner;\r\n<br>\r\npublic class CountNumbers {<br>\r\n    public static void main(String[] args) {<br>\r\n        Scanner sc = new Scanner(System.in);<br>\r\n        int pos = 0, neg = 0, zero = 0;<br>\r\n        char choice;<br>\r\n        \r\n        do {<br>\r\n            System.out.print(\"Enter a number: \");<br>\r\n            int num = sc.nextInt();<br>\r\n            \r\n            if (num > 0) pos++;<br>\r\n            else if (num < 0) neg++;<br>\r\n            else zero++;<br>\r\n\r\n            System.out.print(\"Do you want to continue? (y/n): \");<br>\r\n            choice = sc.next().charAt(0);<br>\r\n        } while (choice == \'y\' || choice == \'Y\');\r\n<br>\r\n        System.out.println(\"Positive: \" + pos + \", Negative: \" + neg + \", Zeros: \" + zero);<br>\r\n        sc.close();\r\n    }\r\n}<br><br>\r\n8. Power Function (x^n)\r\n<br><br>\r\nimport java.util.Scanner;<br>\r\n\r\npublic class PowerFunction {<br>\r\n    public static int power(int x, int n) {<br>\r\n        int result = 1;<br>\r\n        while (n > 0) {<br>\r\n            result *= x;<br>\r\n            n--;<br>\r\n        }<br>\r\n        return result;\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        Scanner sc = new Scanner(System.in);<br>\r\n        System.out.print(\"Enter base and exponent: \");<br>\r\n        int x = sc.nextInt(), n = sc.nextInt();<br>\r\n        System.out.println(x + \"^\" + n + \" = \" + power(x, n));<br>\r\n        sc.close();\r\n    }\r\n}<br><br>\r\n9. Greatest Common Divisor (GCD)\r\n<br><br>\r\nimport java.util.Scanner;<br>\r\n\r\npublic class GCDCalculator {<br>\r\n    public static int gcd(int a, int b) {<br>\r\n        while (b != 0) {<br>\r\n            int temp = b;<br>\r\n            b = a % b;<br>\r\n            a = temp;<br>\r\n        }<br>\r\n        return a;\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        Scanner sc = new Scanner(System.in);<br>\r\n        System.out.print(\"Enter two numbers: \");<br>\r\n        int x = sc.nextInt(), y = sc.nextInt();<br>\r\n        System.out.println(\"GCD: \" + gcd(x, y));<br>\r\n        sc.close();\r\n    }\r\n}\r\n10. Fibonacci Series\r\n<br><br>\r\nimport java.util.Scanner;\r\n<br>\r\npublic class FibonacciSeries {<br>\r\n    public static void fibonacci(int n) {<br>\r\n        int a = 0, b = 1;<br>\r\n        System.out.print(a + \" \" + b + \" \");<br>\r\n        \r\n        for (int i = 2; i < n; i++) {<br>\r\n            int next = a + b;<br>\r\n            System.out.print(next + \" \");<br>\r\n            a = b;<br>\r\n            b = next;\r\n        }\r\n    }<br>\r\n\r\n    public static void main(String[] args) {<br>\r\n        Scanner sc = new Scanner(System.in);<br>\r\n        System.out.print(\"Enter n: \");<br>\r\n        int n = sc.nextInt();<br>\r\n        System.out.print(\"Fibonacci series: \");<br>\r\n        fibonacci(n);<br>\r\n        sc.close();\r\n    }\r\n}');

